ach. It forces to update the variable to one of the specify values Args: app (str): Approach for setting the capacity. It should be fixed, evolved or percentage. """ if app not in self . __capacity_approaches : msg = f "The capacity approach { app } is not available. Please choose between { self . __capacity_approaches } . Evolved approach set as default." print ( msg ) self . _capacity_approach = "evolved" else : self . _capacity_approach = app def generate_instance ( self ) -> Instance : """Generates a new instances for the domain Returns: Instance: New randomly generated instance """ weights = self . _rng . integers ( low = self . min_w , high = self . max_w , size = self . dimension ) profits = self . _rng . integers ( low = self . min_p , high = self . max_p , size = self . dimension ) capacity = 0 # Sets the capacity according to the method if self . capacity_approach == "evolved" : capacity = self . _rng . integers ( 1 , self . max_capacity ) elif self . capacity_approach == "percentage" : capacity = np . sum ( weights , dtype = int ) * self . capacity_ratio elif self . capacity_approach == "fixed" : capacity = self . max_capacity variables = [ int ( capacity )] + list ( itertools . chain ( * zip ( weights , profits ))) return Instance ( variables ) def extract_features ( self , instance : Instance ) -> tuple : """Extract the features of the instance based on the domain Args: instance (Instance): Instance to extract the features from Returns: Tuple[float]: Values of each feature """ _vars = np . asarray ( instance . variables [ 1 :]) weights = _vars [ 0 :: 2 ] profits = _vars [ 1 :: 2 ] avg_eff = np . sum ([ p / w for p , w in zip ( profits , weights )]) / len ( _vars ) capacity = instance . variables [ 0 ] # Sets the capacity according to the method if self . capacity_approach == "percentage" : capacity = np . sum ( weights ) * self . capacity_ratio elif self . _capacity_approach == "fixed" : capacity = self . max_capacity return ( int ( capacity ), np . max ( profits ), np . max ( weights ), np . min ( profits ), np . min ( weights ), avg_eff , np . mean ( _vars ), np . std ( _vars ), ) def extract_features_as_dict ( self , instance : Instance ) -> Mapping [ str , float ]: """Creates a dictionary with the features of the instance. The key are the names of each feature and the values are the values extracted from instance. Args: instance (Instance): Instance to extract the features from Returns: Mapping[str, float]: Dictionary with the names/values of each feature """ if len ( instance . features ) == len ( self . feat_names ): return { k : v for k , v in zip ( self . feat_names , instance . features )} else : features = self . extract_features ( instance ) return { k : v for k , v in zip ( self . feat_names , features )} def from_instance ( self , instance : Instance ) -> Knapsack : variables = instance . variables capacity = variables [ 0 ] weights = variables [ 1 :: 2 ] profits = variables [ 2 :: 2 ] # Sets the capacity according to the method if self . capacity_approach == "percentage" : capacity = np . sum ( weights ) * self . capacity_ratio instance . variables [ 0 ] = capacity elif self . capacity_approach == "fixed" : capacity = self . max_capacity instance . variables [ 0 ] = capacity return Knapsack ( profits = profits , weights = weights , capacity = int ( capacity )) extract_features ( instance ) Extract the features of the instance based on the domain Parameters: instance ( Instance ) – Instance to extract the features from Returns: tuple – Tuple[float]: Values of each feature Source code in digneapy/domains/kp.py 197 198 199 200 201 202 203 204 205 206 207 208 209 210 211 212 213 214 215 216 217 218 219 220 221 222 223 224 225 226 def extract_features ( self , instance : Instance ) -> tuple : """Extract the features of the instance based on the domain Args: instance (Instance): Instance to extract the features from Returns: Tuple[float]: Values of each feature """ _vars = np . asarray ( instance . variabl